# ---------------------------------------------------------------------------
# Builder
# ---------------------------------------------------------------------------


def build_predictions_asset(
    *,
    repo_root: Path,
    predictions_id: str = DEFAULT_PREDICTIONS_ID,
    task_id: str = DEFAULT_TASK_ID,
    spec_version: str = DEFAULT_SPEC_VERSION,
    name: str = DEFAULT_NAME,
    short_description: str = DEFAULT_SHORT_DESCRIPTION,
    description_path: str = DEFAULT_DESCRIPTION_PATH,
    model_id: str | None = DEFAULT_MODEL_ID,
    model_description: str = DEFAULT_MODEL_DESCRIPTION,
    dataset_ids: list[str] | None = None,
    prediction_format: str = DEFAULT_PREDICTION_FORMAT,
    prediction_schema: str = DEFAULT_PREDICTION_SCHEMA,
    instance_count: int | None = DEFAULT_INSTANCE_COUNT,
    metrics_at_creation: dict[str, object] | None = None,
    categories: list[str] | None = None,
    date_created: str = DEFAULT_DATE_CREATED,
    include_description: bool = True,
    include_files_dir: bool = True,
    details_overrides: dict[str, object] | None = None,
    description_body: str | None = None,
) -> Path:
    asset_dir: Path = predictions_asset_dir(
        predictions_id=predictions_id,
        task_id=task_id,
    )
    asset_dir.mkdir(parents=True, exist_ok=True)

    resolved_dataset_ids: list[str] = dataset_ids if dataset_ids is not None else ["test-dataset"]
    resolved_metrics: dict[str, object] | None = (
        metrics_at_creation if metrics_at_creation is not None else {"f1_all": 71.3}
    )
    resolved_categories: list[str] = categories if categories is not None else []

    files_list: list[dict[str, str]] = (
        [
            {
                "path": DEFAULT_PREDICTIONS_FILENAME,
                "description": "Per-instance WSD predictions",
                "format": "jsonl",
            },
        ]
        if include_files_dir
        else []
    )

    details: dict[str, object] = {
        SPEC_VERSION_FIELD: spec_version,
        PREDICTIONS_ID_FIELD: predictions_id,
        NAME_FIELD: name,
        SHORT_DESCRIPTION_FIELD: short_description,
        DESCRIPTION_PATH_FIELD: description_path,
        MODEL_ID_FIELD: model_id,
        MODEL_DESCRIPTION_FIELD: model_description,
        DATASET_IDS_FIELD: resolved_dataset_ids,
        PREDICTION_FORMAT_FIELD: prediction_format,
        PREDICTION_SCHEMA_FIELD: prediction_schema,
        INSTANCE_COUNT_FIELD: instance_count,
        METRICS_AT_CREATION_FIELD: resolved_metrics,
        FILES_FIELD: files_list,
        CATEGORIES_FIELD: resolved_categories,
        CREATED_BY_TASK_FIELD: task_id,
        DATE_CREATED_FIELD: date_created,
    }

    if details_overrides is not None:
        details.update(details_overrides)

    write_json(
        path=predictions_details_path(
            predictions_id=predictions_id,
            task_id=task_id,
        ),
        data=details,
    )

    if include_description:
        frontmatter: dict[str, str | int] = {
            SPEC_VERSION_FIELD: spec_version,
            PREDICTIONS_ID_FIELD: predictions_id,
            "documented_by_task": task_id,
            "date_documented": date_created,
        }
        write_frontmatter_md(
            path=predictions_description_path(
                predictions_id=predictions_id,
                task_id=task_id,
            ),
            frontmatter=frontmatter,
            body=(description_body if description_body is not None else _DESCRIPTION_BODY),
        )

    if include_files_dir:
        files_dir: Path = predictions_files_dir(
            predictions_id=predictions_id,
            task_id=task_id,
        )
        files_dir.mkdir(parents=True, exist_ok=True)
        write_text(
            path=asset_dir / DEFAULT_PREDICTIONS_FILENAME,
            content=(
                '{"instance_id": "d000.s000.t000", '
                '"predicted_sense": "bank%1:17:01::", '
                '"confidence": 0.92, '
                '"context": "He went to the bank to deposit money."}\n'
            ),
        )

    return asset_dir
